// Parse AI response and update document record
  const extractInfo = $('Extract from File').first().json;
  const webhookData = $('Process Document Webhook').first().json.body;
  const aiResponse = $input.first().json;

  let metadata = { category: 'other', description: '', fiscalPeriod: null, isTemplate: false };

  try {
    let responseText = aiResponse.message?.content || aiResponse.text || '';
    const jsonMatch = responseText.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      metadata = JSON.parse(jsonMatch[0]);
    }
  } catch (e) {
    metadata.description = 'Failed to parse AI response';
  }

  return [{
    json: {
      documentId: webhookData.document_id,
      orgId: webhookData.org_id || '',
      extractedText: extractInfo.text || '',
      aiCategory: metadata.category || 'other',
      description: metadata.description || '',
      fiscalPeriod: metadata.fiscalPeriod || null,
      isTemplate: metadata.isTemplate || false
    }
  }];

// Extract context from the calling workflow's payload
const raw = $('Document Retrieval Webhook2').first().json;
const body = raw.body || {};
const payload = body.$json || body;

const grant_id = payload.grant_id || payload.grantId;
const org_id = payload.org_id;
const funder_name = payload.funder_name || 'Not specified';
const narratives = payload.narratives || {};
const sectionsReturned = payload.sectionsReturned || 0;

if (!grant_id || !org_id) {
  return [{
    json: {
      error: true,
      message: `Missing required fields. grant_id: ${grant_id}, org_id: ${org_id}`,
    }
  }];
}

return [{
  json: {
    grant_id,
    org_id,
    funder_name,
    narratives,
    sectionsReturned,
  }
}];

// Build a summary of all documents for the AI to evaluate
const grant = $('Get Grant').first().json;
const allDocs = $('Get All Documents2').all().map(item => item.json);
const context = $('Extract Context').first().json;

if (!allDocs || allDocs.length === 0 || !allDocs[0].id) {
  return [{
    json: {
      error: true,
      message: 'No documents found for this org',
    }
  }];
}

// Build a concise doc list for AI (avoid sending full extracted_text to save tokens)
const docSummaries = allDocs.map((d, i) => ({
  index: i,
  id: d.id,
  name: d.name,
  category: d.ai_category || d.category || 'uncategorized',
  file_type: d.file_type,
  has_content: !!(d.extracted_text && d.extracted_text.length > 0),
  content_preview: (d.extracted_text || '').substring(0, 300),
}));

return [{
  json: {
    grant_title: grant.title || context.funder_name,
    grant_description: grant.description || '',
    funder_name: grant.funder_name || context.funder_name,
    grant_amount: grant.amount || '',
    grant_deadline: grant.deadline || '',
    doc_summaries: docSummaries,
    all_docs: allDocs,
  }
}];

// Build response - pass through all docs since AI filter is removed
 const prepData = $input.first().json;
 const context = $('Extract Context').first().json;
 const allDocs = prepData.all_docs || [];

 const documents = {};
 for (const doc of allDocs) {
   const category = doc.ai_category || doc.category || 'other';
   // If multiple docs share a category, append index to avoid overwrite
   const key = documents[category] ? `${category}_${doc.id.substring(0, 8)}` : category;
   documents[key] = {
     found: true,
     id: doc.id,
     fileName: doc.name,
     category: category,
     extractedText: doc.extracted_text || '',
     extractionStatus: doc.extraction_status,
     createdAt: doc.created_at,
   };
 }

 return [{
   json: {
     success: true,
     grant_id: context.grant_id,
     org_id: context.org_id,
     funder_name: context.funder_name,
     grant_title: prepData.grant_title,
     grant_description: prepData.grant_description,
     totalDocuments: allDocs.length,
     documents,
     narratives: context.narratives,
     sectionsReturned: context.sectionsReturned,
     retrievedAt: new Date().toISOString()
   }
 }];

